type point struct {
	x, y int
}

func distSq(a, b point) int {
	return (a.x-b.x)*(a.x-b.x) + (a.y-b.y)*(a.y-b.y)
}

func solve(pts []point, l, r int) int {
	if r-l < 3 {
		mn := math.MaxInt64
		for i := l; i <= r; i++ {
			for j := i + 1; j <= r; j++ {
				d := distSq(pts[i], pts[j])
				if d < mn {
					mn = d
				}
			}
		}
		return mn
	}

	mid := (l + r) / 2
	midX := pts[mid].x

	dl := solve(pts, l, mid)
	dr := solve(pts, mid+1, r)
	d := dl
	if dr < d {
		d = dr
	}

	var strip []point
	for i := l; i <= r; i++ {
		if (pts[i].x-midX)*(pts[i].x-midX) < d {
			strip = append(strip, pts[i])
		}
	}
	sort.Slice(strip, func(i, j int) bool {
		return strip[i].y < strip[j].y
	})

	for i := 0; i < len(strip); i++ {
		for j := i + 1; j < len(strip) &&
			(strip[j].y-strip[i].y)*(strip[j].y-strip[i].y) < d; j++ {
			dd := distSq(strip[i], strip[j])
			if dd < d {
				d = dd
			}
		}
	}

	return d
}

func ClosestPair(arr []int) int {
	n := len(arr) / 2
	points := make([]point, n)
	for i := 0; i < n; i++ {
		points[i] = point{arr[2*i], arr[2*i+1]}
	}
	sort.Slice(points, func(i, j int) bool {
		if points[i].x != points[j].x {
			return points[i].x < points[j].x
		}
		return points[i].y < points[j].y
	})
	return solve(points, 0, n-1)
}

import java.util.Arrays;
import java.util.ArrayList;
import java.util.List;

public class ClosestPair {

    public static int closestPair(int[] arr) {
        int n = arr.length / 2;
        int[][] points = new int[n][2];
        for (int i = 0; i < n; i++) {
            points[i][0] = arr[2 * i];
            points[i][1] = arr[2 * i + 1];
        }
        Arrays.sort(points, (a, b) -> a[0] != b[0] ? a[0] - b[0] : a[1] - b[1]);
        return solve(points, 0, n - 1);
    }

    private static int distSq(int[] p1, int[] p2) {
        return (p1[0] - p2[0]) * (p1[0] - p2[0]) + (p1[1] - p2[1]) * (p1[1] - p2[1]);
    }

    private static int solve(int[][] points, int l, int r) {
        if (r - l < 3) {
            int min = Integer.MAX_VALUE;
            for (int i = l; i <= r; i++) {
                for (int j = i + 1; j <= r; j++) {
                    min = Math.min(min, distSq(points[i], points[j]));
                }
            }
            return min;
        }

        int mid = (l + r) / 2;
        int midX = points[mid][0];

        int dl = solve(points, l, mid);
        int dr = solve(points, mid + 1, r);
        int d = Math.min(dl, dr);

        List<int[]> strip = new ArrayList<>();
        for (int i = l; i <= r; i++) {
            if ((points[i][0] - midX) * (points[i][0] - midX) < d) {
                strip.add(points[i]);
            }
        }
        strip.sort((a, b) -> a[1] - b[1]);

        for (int i = 0; i < strip.size(); i++) {
            for (int j = i + 1; j < strip.size() &&
                    (strip.get(j)[1] - strip.get(i)[1]) * (strip.get(j)[1] - strip.get(i)[1]) < d; j++) {
                d = Math.min(d, distSq(strip.get(i), strip.get(j)));
            }
        }

        return d;
    }
}

fun closestPair(arr: IntArray): Int {
    val n = arr.size / 2
    data class Point(val x: Int, val y: Int)

    val points = Array(n) { Point(arr[2 * it], arr[2 * it + 1]) }
    points.sortWith(compareBy({ it.x }, { it.y }))

    fun distSq(a: Point, b: Point): Int =
        (a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y)

    fun solve(l: Int, r: Int): Int {
        if (r - l < 3) {
            var mn = Int.MAX_VALUE
            for (i in l..r) {
                for (j in (i + 1)..r) {
                    mn = minOf(mn, distSq(points[i], points[j]))
                }
            }
            return mn
        }

        val mid = (l + r) / 2
        val midX = points[mid].x

        val dl = solve(l, mid)
        val dr = solve(mid + 1, r)
        var d = minOf(dl, dr)

        val strip = mutableListOf<Point>()
        for (i in l..r) {
            if ((points[i].x - midX) * (points[i].x - midX) < d) {
                strip.add(points[i])
            }
        }
        strip.sortBy { it.y }

        for (i in strip.indices) {
            var j = i + 1
            while (j < strip.size && (strip[j].y - strip[i].y) * (strip[j].y - strip[i].y) < d) {
                d = minOf(d, distSq(strip[i], strip[j]))
                j++
            }
        }

        return d
    }

    return solve(0, n - 1)
}

def closest_pair(arr: list[int]) -> int:
    n = len(arr) // 2
    points = [(arr[2 * i], arr[2 * i + 1]) for i in range(n)]
    points.sort()

    def dist_sq(p1, p2):
        return (p1[0] - p2[0]) ** 2 + (p1[1] - p2[1]) ** 2

    def strip_closest(strip, d):
        min_d = d
        strip.sort(key=lambda p: p[1])
        for i in range(len(strip)):
            j = i + 1
            while j < len(strip) and (strip[j][1] - strip[i][1]) ** 2 < min_d:
                min_d = min(min_d, dist_sq(strip[i], strip[j]))
                j += 1
        return min_d

    def solve(pts):
        if len(pts) <= 3:
            min_d = float('inf')
            for i in range(len(pts)):
                for j in range(i + 1, len(pts)):
                    min_d = min(min_d, dist_sq(pts[i], pts[j]))
            return min_d

        mid = len(pts) // 2
        mid_x = pts[mid][0]

        dl = solve(pts[:mid])
        dr = solve(pts[mid:])
        d = min(dl, dr)

        strip = [p for p in pts if (p[0] - mid_x) ** 2 < d]
        return min(d, strip_closest(strip, d))

    return solve(points)

pub fn closest_pair(arr: &[i32]) -> i32 {
    let n = arr.len() / 2;
    let mut points: Vec<(i32, i32)> = (0..n).map(|i| (arr[2 * i], arr[2 * i + 1])).collect();
    points.sort();
    solve(&points, 0, n as i32 - 1)
}

fn dist_sq(a: (i32, i32), b: (i32, i32)) -> i32 {
    (a.0 - b.0) * (a.0 - b.0) + (a.1 - b.1) * (a.1 - b.1)
}

fn solve(pts: &[(i32, i32)], l: i32, r: i32) -> i32 {
    if r - l < 3 {
        let mut mn = i32::MAX;
        for i in l..=r {
            for j in (i + 1)..=r {
                mn = mn.min(dist_sq(pts[i as usize], pts[j as usize]));
            }
        }
        return mn;
    }

    let mid = (l + r) / 2;
    let mid_x = pts[mid as usize].0;

    let dl = solve(pts, l, mid);
    let dr = solve(pts, mid + 1, r);
    let mut d = dl.min(dr);

    let mut strip: Vec<(i32, i32)> = Vec::new();
    for i in l..=r {
        if (pts[i as usize].0 - mid_x) * (pts[i as usize].0 - mid_x) < d {
            strip.push(pts[i as usize]);
        }
    }
    strip.sort_by_key(|p| p.1);

    for i in 0..strip.len() {
        let mut j = i + 1;
        while j < strip.len() && (strip[j].1 - strip[i].1) * (strip[j].1 - strip[i].1) < d {
            d = d.min(dist_sq(strip[i], strip[j]));
            j += 1;
        }
    }

    d
}

object ClosestPair {

  def closestPair(arr: Array[Int]): Int = {
    val n = arr.length / 2
    val points = Array.tabulate(n)(i => (arr(2 * i), arr(2 * i + 1)))
    val sorted = points.sortBy(p => (p._1, p._2))

    def distSq(a: (Int, Int), b: (Int, Int)): Int =
      (a._1 - b._1) * (a._1 - b._1) + (a._2 - b._2) * (a._2 - b._2)

    def solve(l: Int, r: Int): Int = {
      if (r - l < 3) {
        var mn = Int.MaxValue
        for (i <- l to r; j <- (i + 1) to r)
          mn = math.min(mn, distSq(sorted(i), sorted(j)))
        return mn
      }

      val mid = (l + r) / 2
      val midX = sorted(mid)._1

      val dl = solve(l, mid)
      val dr = solve(mid + 1, r)
      var d = math.min(dl, dr)

      val strip = (l to r).filter(i =>
        (sorted(i)._1 - midX) * (sorted(i)._1 - midX) < d
      ).map(sorted(_)).sortBy(_._2)

      for (i <- strip.indices) {
        var j = i + 1
        while (j < strip.length && (strip(j)._2 - strip(i)._2) * (strip(j)._2 - strip(i)._2) < d) {
          d = math.min(d, distSq(strip(i), strip(j)))
          j += 1
        }
      }

      d
    }

    solve(0, n - 1)
  }
}

func closestPair(_ arr: [Int]) -> Int {
    let n = arr.count / 2
    var points: [(Int, Int)] = (0..<n).map { (arr[2 * $0], arr[2 * $0 + 1]) }
    points.sort { $0.0 != $1.0 ? $0.0 < $1.0 : $0.1 < $1.1 }

    func distSq(_ a: (Int, Int), _ b: (Int, Int)) -> Int {
        return (a.0 - b.0) * (a.0 - b.0) + (a.1 - b.1) * (a.1 - b.1)
    }

    if n < 2 { return 0 }

    var best = Int.max
    for i in 0..<(n - 1) {
        for j in (i + 1)..<n {
            best = min(best, distSq(points[i], points[j]))
        }
    }
    return best
}

export function closestPair(arr: number[]): number {
    const n = arr.length / 2;
    const points: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        points.push([arr[2 * i], arr[2 * i + 1]]);
    }
    points.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);

    function distSq(a: [number, number], b: [number, number]): number {
        return (a[0] - b[0]) * (a[0] - b[0]) + (a[1] - b[1]) * (a[1] - b[1]);
    }

    function solve(l: number, r: number): number {
        if (r - l < 3) {
            let min = Infinity;
            for (let i = l; i <= r; i++) {
                for (let j = i + 1; j <= r; j++) {
                    min = Math.min(min, distSq(points[i], points[j]));
                }
            }
            return min;
        }

        const mid = Math.floor((l + r) / 2);
        const midX = points[mid][0];

        const dl = solve(l, mid);
        const dr = solve(mid + 1, r);
        let d = Math.min(dl, dr);

        const strip: [number, number][] = [];
        for (let i = l; i <= r; i++) {
            if ((points[i][0] - midX) * (points[i][0] - midX) < d) {
                strip.push(points[i]);
            }
        }
        strip.sort((a, b) => a[1] - b[1]);

        for (let i = 0; i < strip.length; i++) {
            for (let j = i + 1; j < strip.length &&
                    (strip[j][1] - strip[i][1]) * (strip[j][1] - strip[i][1]) < d; j++) {
                d = Math.min(d, distSq(strip[i], strip[j]));
            }
        }

        return d;
    }

    return solve(0, n - 1);
}
